body:
Followup on similar case to #7171, @em2machine might you also be able to take a look please?

UVM tests/70regs/80examples/05primer and others fails because Verilator creates a new type that should match the default parameters, but does not.

    class uvm_reg_sequence #(type BASE = uvm_sequence#(uvm_reg_item)) extends BASE;
    class uvm_reg_hw_reset_seq extends uvm_reg_sequence #(uvm_sequence #(uvm_reg_item));

the extends matches the BASE=.... type.

<details>
<summary>example</summary>

```
virtual class uvm_object;
endclass

class uvm_factory;
  uvm_object m_type_names[string];

  function uvm_object create_object_by_name(string name);
    uvm_object wrapper;
    if (m_type_names.exists(name)) begin
      wrapper = m_type_names[name];
    end
    else begin
      $display("%%Error: object not found '%s'", name);
      $stop;
    end
    return wrapper;
  endfunction

  function void register(uvm_object obj, string name);
    m_type_names[name] = obj;
  endfunction
endclass

uvm_factory factory;

class uvm_sequence_item extends uvm_object;
endclass

class uvm_reg_item extends uvm_sequence_item;
endclass

virtual class uvm_sequence #(
    type REQ = uvm_sequence_item,
    type RSP = REQ
) extends uvm_object;
endclass

class uvm_reg_sequence #(
    type BASE = uvm_sequence#(uvm_reg_item)
) extends BASE;
  function new;
    factory.register(this, "uvm_reg_sequence");
  endfunction
endclass

class uvm_reg_hw_reset_seq extends uvm_reg_sequence #(uvm_sequence #(uvm_reg_item));
  function new;
    factory.register(this, "uvm_reg_hw_reset_seq");
  endfunction
endclass

module t;
  initial begin
    uvm_reg_hw_reset_seq rsq;

    uvm_reg_sequence seq;
    uvm_object obj;
    int cst;
    string seq_name;

    factory = new;
    rsq = new;

    seq_name = "uvm_reg_hw_reset_seq";

    obj = factory.create_object_by_name(seq_name);
    if (obj == null) $stop;

    cst = $cast(seq, obj);   // <--- fails but should not
    if (!cst || seq == null) $error("%%Error: cast failed");

    if (seq != rsq) $stop;

    $finish;
  end
endmodule
```
</details>

